import { CopyIcon } from '@dynatrace/strato-icons';

import { Item } from '../../../../../navigation/menu/Item.js';
import { Prefix } from '../../../../../navigation/menu/Prefix.js';
import { handleCopyToClipboard } from '../../series-action/utils/handleCopyToClipboard.js';

export const getDefaultAction = <A extends string>(
  item: Record<A, unknown>,
  accessor: A,
  message: string,
) => {
  return (
    <Item
      key={`default-action-copy-${accessor}`}
      onSelect={async () => await handleCopyToClipboard(`${item?.[accessor]}`)}
    >
      <Prefix>
        <CopyIcon />
      </Prefix>
      {message}
    </Item>
  );
};
